export default function Sidebar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    const fetchNotifs = async () => {
      try {
        const res = await api.get('/notifications');
        setUnreadCount(res.data.unreadCount);
      } catch {}
    };
    fetchNotifs();
    const interval = setInterval(fetchNotifs, 30000);
    return () => clearInterval(interval);
  }, []);

  const navItems = roleNavItems[user?.role] || [];

  return (
    <aside className="sidebar" style={{ display: 'flex', flexDirection: 'column', height: '100vh', position: 'sticky', top: 0 }}>
      {/* Logo */}
      <div style={{ padding: '1.5rem', borderBottom: '1px solid var(--border)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <div style={{
            width: 36, height: 36, borderRadius: 8,
            background: 'linear-gradient(135deg, var(--accent), #ff9f7a)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            <svg width="18" height="18" fill="white" viewBox="0 0 24 24">
              <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/>
            </svg>
          </div>
          <div>
            <div style={{ fontFamily: 'var(--font-heading)', fontWeight: 800, fontSize: '0.95rem', lineHeight: 1 }}>3D Print</div>
            <div style={{ fontSize: '0.68rem', color: 'var(--text-muted)', letterSpacing: '0.08em' }}>AVOCARBON</div>
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav style={{ flex: 1, padding: '1rem 0.75rem', overflowY: 'auto' }}>
        {navItems.map(item => {
          const active = location.pathname === item.path ||
            (item.path !== '/' && location.pathname.startsWith(item.path) && item.path !== '/requests/new');
          return (
            <button
              key={item.path}
              onClick={() => navigate(item.path)}
              style={{
                display: 'flex', alignItems: 'center', gap: '0.6rem',
                width: '100%', padding: '0.65rem 0.85rem',
                borderRadius: 'var(--radius)', border: 'none', cursor: 'pointer',
                background: active ? 'var(--accent-dim)' : 'transparent',
                color: active ? 'var(--accent)' : 'var(--text-secondary)',
                fontSize: '0.82rem', fontFamily: 'var(--font-mono)',
                fontWeight: active ? 600 : 400,
                textAlign: 'left', marginBottom: '0.15rem',
                transition: 'var(--transition)',
              }}
              onMouseEnter={e => { if (!active) { e.currentTarget.style.background = 'var(--bg-hover)'; e.currentTarget.style.color = 'var(--text-primary)'; }}}
              onMouseLeave={e => { if (!active) { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'var(--text-secondary)'; }}}
            >
              {icons[item.icon]}
              {item.label}
            </button>
          );
        })}
      </nav>

      {/* Bottom */}
      <div style={{ padding: '1rem 0.75rem', borderTop: '1px solid var(--border)' }}>
        {/* Notifications */}
        <button
          onClick={() => navigate('/notifications')}
          style={{
            display: 'flex', alignItems: 'center', justifyContent: 'space-between',
            width: '100%', padding: '0.65rem 0.85rem',
            borderRadius: 'var(--radius)', border: 'none', cursor: 'pointer',
            background: 'transparent', color: 'var(--text-secondary)',
            fontSize: '0.82rem', fontFamily: 'var(--font-mono)',
            marginBottom: '0.15rem', transition: 'var(--transition)',
          }}
        >
          <span style={{ display: 'flex', alignItems: 'center', gap: '0.6rem' }}>
            {icons.bell} Notifications
          </span>
          {unreadCount > 0 && (
            <span style={{
              background: 'var(--accent)', color: 'white',
              borderRadius: '10px', padding: '0.1rem 0.5rem',
              fontSize: '0.68rem', fontWeight: 700,
            }}>{unreadCount}</span>
          )}
        </button>

        {/* User info */}
        <div style={{
          padding: '0.75rem', background: 'var(--bg-hover)',
          borderRadius: 'var(--radius)', marginBottom: '0.5rem',
        }}>
          <div style={{ fontSize: '0.82rem', fontWeight: 600, color: 'var(--text-primary)' }}>
            {user?.firstName} {user?.lastName}
          </div>
          <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
            {user?.role} · {user?.department}
          </div>
        </div>

        <button
          onClick={logout}
          style={{
            display: 'flex', alignItems: 'center', gap: '0.6rem',
            width: '100%', padding: '0.55rem 0.85rem',
            borderRadius: 'var(--radius)', border: '1px solid var(--border)',
            cursor: 'pointer', background: 'transparent',
            color: 'var(--text-muted)', fontSize: '0.78rem', fontFamily: 'var(--font-mono)',
            transition: 'var(--transition)',
          }}
          onMouseEnter={e => { e.currentTarget.style.color = 'var(--red)'; e.currentTarget.style.borderColor = 'rgba(239,68,68,0.3)'; }}
          onMouseLeave={e => { e.currentTarget.style.color = 'var(--text-muted)'; e.currentTarget.style.borderColor = 'var(--border)'; }}
        >
          {icons.logout} Sign Out
        </button>
      </div>
    </aside>
  );
}
